proof_block:
broadcast use vstd::std_specs::vec::group_vec_axioms;
broadcast use vstd::seq::group_seq_axioms;
broadcast use vstd::set::group_set_axioms;

// Wrap the goal as an implication so we can hypothesize the ensures, force
// z3 to instantiate `maybe_ack_packet`, `send_ack`, `valid_ack` and
// `option_cpacket_to_set_packet` on the same `self_@`/`pkt@` for both runs.
assert(({
    &&& (SingleDelivery::maybe_ack_packet(self_@, pkt@, r1.unwrap()@, CSingleDelivery::option_cpacket_to_set_packet(r1)))
    &&& (r1 is Some ==> valid_ack(r1.unwrap(), pkt))
    &&& (SingleDelivery::maybe_ack_packet(self_@, pkt@, r2.unwrap()@, CSingleDelivery::option_cpacket_to_set_packet(r2)))
    &&& (r2 is Some ==> valid_ack(r2.unwrap(), pkt))
}) ==> det_maybe_ack_packet_impl_equal(r1, r2)) by {
    let pre = self_@;
    let p = pkt@;
    let s1 = CSingleDelivery::option_cpacket_to_set_packet(r1);
    let s2 = CSingleDelivery::option_cpacket_to_set_packet(r2);

    if (SingleDelivery::maybe_ack_packet(pre, p, r1.unwrap()@, s1))
       && (r1 is Some ==> valid_ack(r1.unwrap(), pkt))
       && (SingleDelivery::maybe_ack_packet(pre, p, r2.unwrap()@, s2))
       && (r2 is Some ==> valid_ack(r2.unwrap(), pkt)) {

        // `should_ack_single_message` is a function of (self_@, pkt@) alone,
        // so it has the same value across both runs.  Case split on it; the
        // two branches each pin the Some/None tag of r1 and r2 and (in the
        // Some branch) the inner CPacket up to a structural equality.
        if pre.should_ack_single_message(p) {
            // send_ack pins `acks == set![ack]`; a singleton set can't be
            // empty, so r being None (which yields Set::empty()) is a
            // contradiction.  Use that to force both r1 and r2 to be Some.
            if r1 is None {
                assert(s1 =~= Set::<Packet>::empty());
                assert(SingleDelivery::send_ack(pre, p, r1.unwrap()@, s1));
                assert(s1 =~= set!{ r1.unwrap()@ });
                assert(s1.contains(r1.unwrap()@));
                assert(false);
            }
            if r2 is None {
                assert(s2 =~= Set::<Packet>::empty());
                assert(SingleDelivery::send_ack(pre, p, r2.unwrap()@, s2));
                assert(s2 =~= set!{ r2.unwrap()@ });
                assert(s2.contains(r2.unwrap()@));
                assert(false);
            }
            assert(r1 is Some);
            assert(r2 is Some);

            // send_ack pins `ack.src@ == pkt.dst@` and `ack.dst@ == pkt.src@`
            // for both runs, so the two acks agree on src and dst at the
            // abstract (AbstractEndPoint / Seq<u8>) level.
            assert(SingleDelivery::send_ack(pre, p, r1.unwrap()@, s1));
            assert(SingleDelivery::send_ack(pre, p, r2.unwrap()@, s2));
            assert(r1.unwrap()@.src == p.dst);
            assert(r2.unwrap()@.src == p.dst);
            assert(r1.unwrap()@.dst == p.src);
            assert(r2.unwrap()@.dst == p.src);
            // CPacket@.{src,dst} is AbstractEndPoint { id: cpacket.{src,dst}.id@ },
            // so the structural equality at the AbstractEndPoint level gives
            // equality at the inner Seq<u8> level.
            assert(r1.unwrap().src@ == p.dst);
            assert(r2.unwrap().src@ == p.dst);
            assert(r1.unwrap().dst@ == p.src);
            assert(r2.unwrap().dst@ == p.src);
            assert(r1.unwrap().src@ == r2.unwrap().src@);
            assert(r1.unwrap().dst@ == r2.unwrap().dst@);
            assert(r1.unwrap().src.id@ == r2.unwrap().src.id@);
            assert(r1.unwrap().dst.id@ == r2.unwrap().dst.id@);
            assert(r1.unwrap().src.id@ =~= r2.unwrap().src.id@);
            assert(r1.unwrap().dst.id@ =~= r2.unwrap().dst.id@);

            // send_ack also pins the abstract message to an Ack carrying the
            // original packet's seqno; only CSingleMessage::Ack maps to a
            // SingleMessage::Ack via CSingleMessage::view, so the concrete
            // tag must be Ack on both runs and the inner u64 must agree.
            assert(r1.unwrap()@.msg is Ack);
            assert(r2.unwrap()@.msg is Ack);
            assert(r1.unwrap().msg is Ack);
            assert(r2.unwrap().msg is Ack);
            assert(r1.unwrap().msg.arrow_Ack_ack_seqno()
                == pkt.msg.arrow_Message_seqno());
            assert(r2.unwrap().msg.arrow_Ack_ack_seqno()
                == pkt.msg.arrow_Message_seqno());
            assert(r1.unwrap().msg.arrow_Ack_ack_seqno()
                == r2.unwrap().msg.arrow_Ack_ack_seqno());
            // CSingleMessage::Ack carries a single u64; equal tag + equal
            // field collapses to structural enum equality.
            assert(r1.unwrap().msg == r2.unwrap().msg);
        } else {
            // !should_ack ⇒ acks.is_empty(); a singleton set isn't empty,
            // so r being Some is a contradiction.  Force both to be None.
            if r1 is Some {
                assert(s1 =~= set!{ r1.unwrap()@ });
                assert(s1.is_empty());
                assert(s1.contains(r1.unwrap()@));
                assert(false);
            }
            if r2 is Some {
                assert(s2 =~= set!{ r2.unwrap()@ });
                assert(s2.is_empty());
                assert(s2.contains(r2.unwrap()@));
                assert(false);
            }
            assert(r1 is None);
            assert(r2 is None);
        }
    }
};
